rows.customCode:
(() => {
  // pcbw: Scene-and-Lore Adventure Bot - scene progression engine with lore injection
  if (window.__pcbw_sceneLoreInit) return;
  window.__pcbw_sceneLoreInit = true;

  var SCENES = {
    tavern: {
      name: "The Hollow Crown Tavern",
      description: "A warm, dimly lit tavern with oak beams and a crackling hearth. The air smells of ale and wood smoke. Murmured conversations fill the room.",
      exits: ["market", "forest"],
      lore: "The Hollow Crown has stood at the crossroads for three centuries. Its keeper, Old Maren, is said to know every secret that passes through these lands."
    },
    market: {
      name: "Crossroads Market",
      description: "A bustling open-air market where merchants hawk wares from distant lands. Colorful banners flutter overhead and the sound of haggling fills the air.",
      exits: ["tavern", "tower"],
      lore: "The Crossroads Market sits where three ancient trade routes converge. The Merchant Guild maintains order here, but pickpockets and spies are common."
    },
    forest: {
      name: "Whisperwood",
      description: "An ancient forest where pale light filters through dense canopy. Strange mushrooms glow faintly at the base of twisted trees. The air hums with unseen energy.",
      exits: ["tavern", "ruins"],
      lore: "Whisperwood is the last remnant of the great Eldertree Forest. The trees here are semi-sentient and the forest itself sometimes rearranges its paths to confuse intruders."
    },
    tower: {
      name: "The Astrologer's Tower",
      description: "A tall, narrow tower of dark stone that seems to lean slightly against the sky. Star charts and arcane instruments are visible through the open windows above.",
      exits: ["market", "ruins"],
      lore: "The tower belongs to Vaelith, an astrologer who has not been seen in years. Locals say lights still burn in the upper floors at night."
    },
    ruins: {
      name: "The Sunken Temple Ruins",
      description: "Crumbling stone pillars rise from overgrown ground. A staircase descends into darkness. Ancient carvings cover every surface, depicting forgotten rituals.",
      exits: ["forest", "tower"],
      lore: "These are the remains of a temple to a forgotten deity. Scholars debate whether it was a place of worship or imprisonment. Strange sounds echo from below at certain moon phases."
    }
  };

  function initAdventureState() {
    oc.thread.customData ||= {};
    if (!oc.thread.customData.__pcbw_scene) {
      oc.thread.customData.__pcbw_scene = "tavern";
    }
    if (!Array.isArray(oc.thread.customData.__pcbw_visited)) {
      oc.thread.customData.__pcbw_visited = ["tavern"];
    }
    if (!Array.isArray(oc.thread.customData.__pcbw_discoveredLore)) {
      oc.thread.customData.__pcbw_discoveredLore = [];
    }
    if (typeof oc.thread.customData.__pcbw_turnCount !== "number") {
      oc.thread.customData.__pcbw_turnCount = 0;
    }
  }

  function getCurrentScene() {
    initAdventureState();
    return SCENES[oc.thread.customData.__pcbw_scene] || SCENES.tavern;
  }

  function changeScene(sceneKey) {
    initAdventureState();
    if (!SCENES[sceneKey]) return false;
    var current = oc.thread.customData.__pcbw_scene;
    var currentScene = SCENES[current];
    if (currentScene.exits.indexOf(sceneKey) === -1) return false;

    oc.thread.customData.__pcbw_scene = sceneKey;
    if (oc.thread.customData.__pcbw_visited.indexOf(sceneKey) === -1) {
      oc.thread.customData.__pcbw_visited.push(sceneKey);
    }
    return true;
  }

  oc.thread.on("MessageAdded", function(msg) {
    if (msg.author !== "user") return;
    initAdventureState();
    oc.thread.customData.__pcbw_turnCount += 1;

    var text = (msg.content || "").trim().toLowerCase();

    // Scene navigation: /go <location>
    if (text.startsWith("/go ")) {
      var dest = text.slice(4).trim();
      if (changeScene(dest)) {
        var scene = getCurrentScene();
        oc.thread.messages.push({
          author: "system",
          content: "--- Scene Change ---\nYou arrive at: " + scene.name + "\n" + scene.description + "\nExits: " + scene.exits.join(", "),
          hiddenFrom: [],
          expectsReply: false
        });
      } else {
        var current = getCurrentScene();
        oc.thread.messages.push({
          author: "system",
          content: "You cannot go there from here. Available exits: " + current.exits.join(", "),
          hiddenFrom: ["ai"],
          expectsReply: false
        });
      }
      return;
    }

    // Look around
    if (text === "/look") {
      var scene = getCurrentScene();
      oc.thread.messages.push({
        author: "system",
        content: "--- " + scene.name + " ---\n" + scene.description + "\nExits: " + scene.exits.join(", "),
        hiddenFrom: [],
        expectsReply: false
      });
      return;
    }

    // Investigate lore
    if (text === "/lore") {
      var scene = getCurrentScene();
      var sceneKey = oc.thread.customData.__pcbw_scene;
      if (oc.thread.customData.__pcbw_discoveredLore.indexOf(sceneKey) === -1) {
        oc.thread.customData.__pcbw_discoveredLore.push(sceneKey);
      }
      oc.thread.messages.push({
        author: "system",
        content: "--- Lore Discovered ---\n" + scene.lore,
        hiddenFrom: [],
        expectsReply: false
      });
      return;
    }

    // Map of visited locations
    if (text === "/map") {
      var visited = oc.thread.customData.__pcbw_visited;
      var currentKey = oc.thread.customData.__pcbw_scene;
      var lines = visited.map(function(k) {
        var s = SCENES[k];
        var marker = k === currentKey ? " <-- you are here" : "";
        return "- " + (s ? s.name : k) + marker;
      });
      oc.thread.messages.push({
        author: "system",
        content: "--- Your Map ---\nPlaces visited:\n" + lines.join("\n"),
        hiddenFrom: ["ai"],
        expectsReply: false
      });
      return;
    }
  });

  // Inject scene context into AI responses
  oc.thread.on("MessageAdding", function(msg) {
    if (msg.author !== "ai") return;
    initAdventureState();
    var scene = getCurrentScene();
    var loreKnown = oc.thread.customData.__pcbw_discoveredLore || [];
    var turnCount = oc.thread.customData.__pcbw_turnCount || 0;

    var context = "[SCENE CONTEXT] Current location: " + scene.name + ". " + scene.description;
    context += " Available exits: " + scene.exits.join(", ") + ".";

    if (loreKnown.length > 0) {
      var loreParts = loreKnown.map(function(k) {
        return SCENES[k] ? SCENES[k].name + ": " + SCENES[k].lore : "";
      }).filter(function(s) { return s; });
      context += " [KNOWN LORE] " + loreParts.join(" | ");
    }

    if (turnCount > 5) {
      context += " [PACING] The adventure is progressing. Build tension and introduce narrative hooks.";
    }
    if (turnCount > 15) {
      context += " [PACING] The story is well underway. Begin weaving discovered lore into plot threads.";
    }

    oc.character.reminderMessage = context + " Stay in character as the narrator. Describe the world vividly. React to the player actions within the current scene.";
  });
})();
